import boto3
import json
import logging
from typing import Dict, Any, Callable
from datetime import datetime

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SQSWorker:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.queue_url = queue_url
        self.sqs = boto3.client('sqs', region_name=region_name)
        self.message_handlers: Dict[str, Callable] = {}
        self.running = False
    
    def register_handler(self, message_type: str, handler: Callable):
        """Register a handler for a specific message type"""
        self.message_handlers[message_type] = handler
    
    def _parse_message(self, message_body: str) -> Dict[str, Any]:
        """Parse message body and return dictionary"""
        try:
            if isinstance(message_body, str):
                return json.loads(message_body)
            return message_body
        except json.JSONDecodeError:
            logger.error(f"Failed to parse message: {message_body}")
            return {}
    
    def _execute_action(self, message_data: Dict[str, Any]):
        """Execute action based on message content"""
        message_type = message_data.get('type')
        if not message_type:
            logger.warning("Message type not found")
            return False
        
        handler = self.message_handlers.get(message_type)
        if not handler:
            logger.warning(f"No handler found for message type: {message_type}")
            return False
        
        try:
            handler(message_data)
            logger.info(f"Successfully processed message type: {message_type}")
            return True
        except Exception as e:
            logger.error(f"Error processing message type {message_type}: {str(e)}")
            return False
    
    def process_message(self, message: Dict[str, Any]) -> bool:
        """Process a single SQS message"""
        try:
            message_body = message.get('Body', '')
            message_data = self._parse_message(message_body)
            
            if not message_data:
                logger.warning("Empty message data")
                return False
            
            # Add message metadata
            message_data['message_id'] = message.get('MessageId')
            message_data['receipt_handle'] = message.get('ReceiptHandle')
            message_data['processed_at'] = datetime.now().isoformat()
            
            success = self._execute_action(message_data)
            
            if success:
                # Delete message from queue if successful
                self.sqs.delete_message(
                    QueueUrl=self.queue_url,
                    ReceiptHandle=message.get('ReceiptHandle')
                )
                return True
            
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            return False
        
        return False
    
    def start_worker(self, max_messages: int = 10, wait_time: int = 20):
        """Start polling and processing messages"""
        self.running = True
        logger.info("Starting SQS worker...")
        
        while self.running:
            try:
                response = self.sqs.receive_message(
                    QueueUrl=self.queue_url,
                    MaxNumberOfMessages=max_messages,
                    WaitTimeSeconds=wait_time,
                    MessageAttributeNames=['All']
                )
                
                messages = response.get('Messages', [])
                if not messages:
                    logger.info("No messages received")
                    continue
                
                logger.info(f"Received {len(messages)} messages")
                
                for message in messages:
                    self.process_message(message)
                    
            except Exception as e:
                logger.error(f"Error in worker loop: {str(e)}")
                continue
    
    def stop_worker(self):
        """Stop the worker"""
        self.running = False
        logger.info("Worker stopped")

